#!/usr/bin/env bun
/**
 * Analyze Gmail communication patterns for the last 30 days.
 * Metrics:
 * 1. TotalSent: Number of emails sent in the last 30 days
 * 2. TopRecipients: Top 3 recipients by email count
 * 3. ReplyRate: % of sent emails that got at least one reply back to inbox
 * 4. AvgResponseTimeHours: Average time taken to reply to received emails (hours)
 */

import { execSync } from "child_process";

const USER_EMAIL = "timepassmovieeasy@gmail.com";
const CUTOFF_DATE = new Date("2026-02-15T00:00:00Z"); // 30 days before 2026-03-17
const CUTOFF_EPOCH_MS = CUTOFF_DATE.getTime();

function gws(params: string): any {
  try {
    const output = execSync(`gws gmail users messages get --params '${params}'`, {
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"],
    }).replace(/Using keyring backend: keyring\n?/g, "").trim();
    return JSON.parse(output);
  } catch (e: any) {
    return null;
  }
}

function gwsList(query: string, labelIds?: string): any[] {
  const all: any[] = [];
  let pageToken: string | undefined;
  let page = 0;
  while (page < 20) {
    const paramsObj: any = {
      userId: "me",
      maxResults: 500,
      q: query,
    };
    if (labelIds) paramsObj.labelIds = labelIds;
    if (pageToken) paramsObj.pageToken = pageToken;
    const paramsStr = JSON.stringify(paramsObj);
    try {
      const raw = execSync(`gws gmail users messages list --params '${paramsStr}'`, {
        encoding: "utf-8",
        stdio: ["pipe", "pipe", "pipe"],
      });
      // Parse NDJSON lines
      const lines = raw
        .replace(/Using keyring backend: keyring\n?/g, "")
        .trim()
        .split("\n")
        .filter((l) => l.trim());

      for (const line of lines) {
        try {
          const parsed = JSON.parse(line);
          if (parsed.messages) {
            all.push(...parsed.messages);
          }
          if (parsed.nextPageToken) {
            pageToken = parsed.nextPageToken;
          } else {
            pageToken = undefined;
          }
        } catch {}
      }
    } catch (e) {
      break;
    }
    page++;
    if (!pageToken) break;
  }
  return all;
}

function getMsgMetadata(id: string): any {
  try {
    const raw = execSync(
      `gws gmail users messages get --params '{"userId":"me","id":"${id}","format":"metadata","metadataHeaders":["To","From","Date","Subject","Message-ID","In-Reply-To","References"]}'`,
      { encoding: "utf-8", stdio: ["pipe", "pipe", "pipe"] }
    ).replace(/Using keyring backend: keyring\n?/g, "").trim();
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function getHeader(msg: any, name: string): string {
  if (!msg?.payload?.headers) return "";
  const h = msg.payload.headers.find(
    (x: any) => x.name.toLowerCase() === name.toLowerCase()
  );
  return h?.value || "";
}

function extractEmails(str: string): string[] {
  const emailRegex = /[\w.+%-]+@[\w.-]+\.[a-z]{2,}/gi;
  return (str.match(emailRegex) || []).map((e) => e.toLowerCase());
}

function parseDate(str: string): Date | null {
  if (!str) return null;
  try {
    return new Date(str);
  } catch {
    return null;
  }
}

async function main() {
  console.log("Step 1: Fetching SENT emails (all time)...");
  const sentMessages = gwsList("in:sent", "SENT");
  console.log(`Found ${sentMessages.length} sent messages total`);

  // Fetch full metadata for each sent message
  const sentDetails: any[] = [];
  for (const m of sentMessages) {
    const detail = getMsgMetadata(m.id);
    if (detail) {
      const dateStr = getHeader(detail, "Date");
      const date = dateStr ? new Date(detail.internalDate ? Number(detail.internalDate) : dateStr) : null;
      if (date && date.getTime() >= CUTOFF_EPOCH_MS) {
        sentDetails.push(detail);
      }
    }
  }
  console.log(`Sent emails in last 30 days: ${sentDetails.length}`);

  // ---- METRIC 1: TotalSent ----
  const totalSent = sentDetails.length;

  // ---- METRIC 2: TopRecipients ----
  const recipientCounts: Record<string, number> = {};
  for (const msg of sentDetails) {
    const toHeader = getHeader(msg, "To");
    const ccHeader = getHeader(msg, "Cc");
    const allTo = toHeader + "," + ccHeader;
    const emails = extractEmails(allTo).filter((e) => e !== USER_EMAIL.toLowerCase());
    for (const email of emails) {
      recipientCounts[email] = (recipientCounts[email] || 0) + 1;
    }
  }
  const topRecipients = Object.entries(recipientCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  // ---- METRIC 3: ReplyRate ----
  // For each sent email, check if the thread has a reply in INBOX from someone else
  console.log("\nStep 2: Fetching INBOX emails to analyze threads...");
  const inboxMessages = gwsList("in:inbox after:2026/02/15");
  console.log(`Inbox messages in last 30 days: ${inboxMessages.length}`);

  // Build a set of thread IDs that have inbox messages
  const inboxThreadIds = new Set(inboxMessages.map((m) => m.threadId));

  let sentWithReply = 0;
  for (const sentMsg of sentDetails) {
    if (inboxThreadIds.has(sentMsg.threadId)) {
      sentWithReply++;
    }
  }
  const replyRate = totalSent > 0 ? ((sentWithReply / totalSent) * 100).toFixed(1) : "0.0";

  // ---- METRIC 4: AvgResponseTimeHours ----
  // For each inbox email received (not from self), find my reply in the same thread
  // Response time = time of my sent email - time of the received email I'm replying to
  console.log("\nStep 3: Computing average response time...");

  // Get full metadata for inbox messages
  const responseTimes: number[] = [];

  // Group inbox messages by threadId
  const threadToInboxMsgs: Record<string, any[]> = {};
  for (const m of inboxMessages) {
    if (!threadToInboxMsgs[m.threadId]) threadToInboxMsgs[m.threadId] = [];
    threadToInboxMsgs[m.threadId].push(m);
  }

  // For sent messages, find the inbox message in the same thread that came before
  for (const sentMsg of sentDetails) {
    const sentTime = Number(sentMsg.internalDate);
    const threadId = sentMsg.threadId;

    if (!threadToInboxMsgs[threadId]) continue;

    // Find inbox messages in this thread that arrived before this sent message
    // and are not from the user themselves
    const inboxMsgsInThread = threadToInboxMsgs[threadId];

    // We need to check which of these were received before the sent message
    // The inboxMessages list only has id/threadId, we need the internalDate
    // Use a heuristic: fetch details for threads with multiple messages
    for (const inboxMsg of inboxMsgsInThread) {
      const detail = getMsgMetadata(inboxMsg.id);
      if (!detail) continue;

      const fromHeader = getHeader(detail, "From");
      const fromEmails = extractEmails(fromHeader);

      // Skip if from self
      if (fromEmails.includes(USER_EMAIL.toLowerCase())) continue;

      // Labels check - must be in inbox
      const labels: string[] = detail.labelIds || [];
      if (!labels.includes("INBOX")) continue;

      const inboxTime = Number(detail.internalDate);
      if (inboxTime < sentTime) {
        // This inbox message came before the sent message, in the same thread
        const diff = sentTime - inboxTime;
        const diffHours = diff / (1000 * 60 * 60);
        if (diffHours < 720) { // ignore outliers > 30 days
          responseTimes.push(diffHours);
        }
        break; // only use the most recent inbox msg before sent
      }
    }
  }

  const avgResponseHours =
    responseTimes.length > 0
      ? (responseTimes.reduce((a, b) => a + b, 0) / responseTimes.length).toFixed(1)
      : "N/A";

  console.log("\n===== RESULTS =====");
  console.log(`TotalSent: ${totalSent}`);
  const topRecipientsStr =
    topRecipients.length > 0
      ? topRecipients.map(([email, count]) => `${email} (${count})`).join(", ")
      : "N/A";
  console.log(`TopRecipients: ${topRecipientsStr}`);
  console.log(`ReplyRate: ${replyRate}%`);
  console.log(`AvgResponseTimeHours: ${avgResponseHours}`);
}

main().catch(console.error);

#!/usr/bin/env bun
/**
 * Analyze Gmail communication patterns for the last 30 days.
 * Metrics:
 * 1. TotalSent: Number of emails sent in the last 30 days
 * 2. TopRecipients: Top 3 recipients by email count
 * 3. ReplyRate: % of sent emails that got at least one reply back into inbox
 * 4. AvgResponseTimeHours: Average time taken to reply to received emails
 */

import { execSync } from "child_process";

const USER_EMAIL = "timepassmovieeasy@gmail.com";
// 30 days before today (2026-03-17)
const CUTOFF_EPOCH_MS = new Date("2026-02-15T00:00:00Z").getTime();

function runGws(args: string): string {
  try {
    return execSync(`gws ${args}`, {
      encoding: "utf-8",
      stdio: ["pipe", "pipe", "pipe"],
    }).replace(/Using keyring backend: keyring\n?/g, "").trim();
  } catch (e: any) {
    const out = (e.stdout || "").replace(/Using keyring backend: keyring\n?/g, "").trim();
    return out;
  }
}

function listMessages(query: string): { id: string; threadId: string }[] {
  const raw = runGws(
    `gmail users messages list --params '{"userId":"me","q":"${query}","maxResults":500}' --page-all --page-limit 20`
  );
  const results: { id: string; threadId: string }[] = [];
  for (const line of raw.split("\n")) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    try {
      const parsed = JSON.parse(trimmed);
      if (parsed.messages) {
        results.push(...parsed.messages);
      }
    } catch {}
  }
  return results;
}

function getMessageMetadata(id: string): any {
  const raw = runGws(
    `gmail users messages get --params '{"userId":"me","id":"${id}","format":"metadata","metadataHeaders":["To","From","Date","Subject","Cc"]}'`
  );
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function getHeader(msg: any, name: string): string {
  if (!msg?.payload?.headers) return "";
  const h = msg.payload.headers.find(
    (x: any) => x.name.toLowerCase() === name.toLowerCase()
  );
  return h?.value || "";
}

function extractEmails(str: string): string[] {
  const emailRegex = /[\w.+%-]+@[\w.-]+\.[a-z]{2,}/gi;
  return (str.match(emailRegex) || []).map((e) => e.toLowerCase());
}

async function main() {
  console.log("=== Gmail Communication Analysis (Last 30 Days) ===\n");

  // =============================================
  // STEP 1: Get all SENT messages in last 30 days
  // =============================================
  console.log("Step 1: Fetching sent messages from last 30 days...");
  // Gmail query: in:sent after:2026/02/15
  const allSentRaw = listMessages("in:sent");
  console.log(`  Total SENT label messages: ${allSentRaw.length}`);

  // Filter by internalDate >= cutoff
  const sentDetails: any[] = [];
  for (const m of allSentRaw) {
    const detail = getMessageMetadata(m.id);
    if (!detail) continue;
    const ts = Number(detail.internalDate);
    if (ts >= CUTOFF_EPOCH_MS) {
      sentDetails.push(detail);
    }
  }
  console.log(`  Sent messages within last 30 days: ${sentDetails.length}`);

  // Check for any sent messages in inbox/drafts from user in last 30 days
  // (Some sent messages don't get SENT label if they were sent from other clients)
  console.log("\nStep 2: Also checking messages FROM user in last 30 days...");
  const fromUserRaw = listMessages(`from:${USER_EMAIL} after:2026/02/15`);
  console.log(`  Messages from user (all labels) in last 30 days: ${fromUserRaw.length}`);

  // Check each and only include those with SENT label
  const extraSentIds = new Set(sentDetails.map((d) => d.id));
  for (const m of fromUserRaw) {
    if (extraSentIds.has(m.id)) continue;
    const detail = getMessageMetadata(m.id);
    if (!detail) continue;
    const labels: string[] = detail.labelIds || [];
    if (labels.includes("SENT")) {
      sentDetails.push(detail);
      extraSentIds.add(m.id);
    }
  }
  console.log(`  Total unique sent messages: ${sentDetails.length}`);

  // =============================================
  // METRIC 1: TotalSent
  // =============================================
  const totalSent = sentDetails.length;

  // =============================================
  // METRIC 2: TopRecipients
  // =============================================
  console.log("\nStep 3: Analyzing recipients...");
  const recipientCounts: Record<string, number> = {};
  for (const msg of sentDetails) {
    const toHeader = getHeader(msg, "To");
    const ccHeader = getHeader(msg, "Cc");
    const allTo = [toHeader, ccHeader].join(",");
    const emails = extractEmails(allTo).filter(
      (e) => e !== USER_EMAIL.toLowerCase()
    );
    for (const email of emails) {
      recipientCounts[email] = (recipientCounts[email] || 0) + 1;
    }
  }
  const topRecipients = Object.entries(recipientCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

