#!/usr/bin/env bun
/**
 * Analyze Gmail communication patterns for the last 30 days.
 * Metrics:
 * 1. TotalSent: Number of emails sent in the last 30 days
 * 2. TopRecipients: Top 3 recipients by email count
 * 3. ReplyRate: % of sent emails that got at least one reply back into inbox
 * 4. AvgResponseTimeHours: Average time taken to reply to received emails (hours)
 */

import { spawnSync } from "child_process";

const USER_EMAIL = "timepassmovieeasy@gmail.com";
// 30 days before today (2026-03-17)
const CUTOFF_EPOCH_MS = new Date("2026-02-15T00:00:00Z").getTime();

function gwsSpawn(args: string[]): string {
  const result = spawnSync("gws", args, { encoding: "utf-8" });
  const out = (result.stdout || "")
    .replace(/Using keyring backend: keyring\n?/g, "")
    .trim();
  return out;
}

function listMessages(query: string): { id: string; threadId: string }[] {
  const raw = gwsSpawn([
    "gmail",
    "users",
    "messages",
    "list",
    "--params",
    JSON.stringify({ userId: "me", q: query, maxResults: 500 }),
    "--page-all",
    "--page-limit",
    "20",
  ]);
  const results: { id: string; threadId: string }[] = [];
  for (const line of raw.split("\n")) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    try {
      const parsed = JSON.parse(trimmed);
      if (parsed.messages) {
        results.push(...parsed.messages);
      }
    } catch {}
  }
  return results;
}

function getMessageMetadata(id: string): any {
  const raw = gwsSpawn([
    "gmail",
    "users",
    "messages",
    "get",
    "--params",
    JSON.stringify({
      userId: "me",
      id,
      format: "metadata",
      metadataHeaders: ["To", "From", "Date", "Subject", "Cc"],
    }),
  ]);
  try {
    return JSON.parse(raw);
  } catch {
    return null;
  }
}

function getHeader(msg: any, name: string): string {
  if (!msg?.payload?.headers) return "";
  const h = msg.payload.headers.find(
    (x: any) => x.name.toLowerCase() === name.toLowerCase()
  );
  return h?.value || "";
}

function extractEmails(str: string): string[] {
  const emailRegex = /[\w.+%-]+@[\w.-]+\.[a-z]{2,}/gi;
  return (str.match(emailRegex) || []).map((e) => e.toLowerCase());
}

async function main() {
  console.log("=== Gmail Communication Analysis (Last 30 Days) ===\n");

  // =============================================
  // STEP 1: Get all SENT messages
  // =============================================
  console.log("Step 1: Fetching SENT messages...");
  const allSentRaw = listMessages("in:sent");
  console.log(`  Total SENT label messages found: ${allSentRaw.length}`);

  // Fetch full metadata and filter by date
  const sentDetails: any[] = [];
  for (const m of allSentRaw) {
    const detail = getMessageMetadata(m.id);
    if (!detail) continue;
    const ts = Number(detail.internalDate);
    if (ts >= CUTOFF_EPOCH_MS) {
      sentDetails.push(detail);
    }
  }
  console.log(`  Sent messages in last 30 days: ${sentDetails.length}`);

  // Also check messages from user across all labels in last 30 days
  console.log("\nStep 2: Checking all messages FROM user in last 30 days...");
  const fromUserRaw = listMessages(`from:${USER_EMAIL} after:2026/02/15`);
  console.log(
    `  Messages from user (all labels) in last 30 days: ${fromUserRaw.length}`
  );

  const sentIds = new Set(sentDetails.map((d) => d.id));
  for (const m of fromUserRaw) {
    if (sentIds.has(m.id)) continue;
    const detail = getMessageMetadata(m.id);
    if (!detail) continue;
    const labels: string[] = detail.labelIds || [];
    if (labels.includes("SENT")) {
      sentDetails.push(detail);
      sentIds.add(m.id);
    }
  }
  console.log(`  Total unique sent messages (last 30 days): ${sentDetails.length}`);

  // =============================================
  // METRIC 1: TotalSent
  // =============================================
  const totalSent = sentDetails.length;

  // =============================================
  // METRIC 2: TopRecipients
  // =============================================
  console.log("\nStep 3: Analyzing recipients...");
  const recipientCounts: Record<string, number> = {};
  for (const msg of sentDetails) {
    const toHeader = getHeader(msg, "To");
    const ccHeader = getHeader(msg, "Cc");
    const allTo = [toHeader, ccHeader].join(",");
    const emails = extractEmails(allTo).filter(
      (e) => e !== USER_EMAIL.toLowerCase()
    );
    for (const email of emails) {
      recipientCounts[email] = (recipientCounts[email] || 0) + 1;
    }
  }
  const topRecipients = Object.entries(recipientCounts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 3);

  // =============================================
  // METRIC 3: ReplyRate
  // =============================================
  console.log("\nStep 4: Fetching inbox messages for reply rate...");
  const inboxRaw = listMessages("in:inbox");
  console.log(`  Inbox messages found: ${inboxRaw.length}`);

  // Build set of threadIds in INBOX
  const inboxThreadIds = new Set(inboxRaw.map((m) => m.threadId));

  // Count how many sent threads had a reply in inbox
  let sentThreadsWithReply = 0;
  const checkedThreads = new Set<string>();

  for (const sentMsg of sentDetails) {
    const threadId = sentMsg.threadId;
    if (checkedThreads.has(threadId)) continue;
    checkedThreads.add(threadId);
    if (inboxThreadIds.has(threadId)) {
      sentThreadsWithReply++;
    }
  }

  const replyRate =
    totalSent > 0
      ? ((sentThreadsWithReply / totalSent) * 100).toFixed(1)
      : "0.0";

  // =============================================
  // METRIC 4: AvgResponseTimeHours
  // =============================================
  console.log("\nStep 5: Computing average response time...");

  // Group inbox messages by threadId
  const inboxByThread: Record<string, { id: string; threadId: string }[]> = {};
  for (const m of inboxRaw) {
    if (!inboxByThread[m.threadId]) inboxByThread[m.threadId] = [];
    inboxByThread[m.threadId].push(m);
  }

  const responseTimes: number[] = [];

  // For each sent message, find if there was an inbox message from someone else
  // that arrived BEFORE the sent message in the same thread
  for (const sentMsg of sentDetails) {
    const threadId = sentMsg.threadId;
    const sentTime = Number(sentMsg.internalDate);

    const inboxMsgsInThread = inboxByThread[threadId];
    if (!inboxMsgsInThread || inboxMsgsInThread.length === 0) continue;

    // Get details for inbox messages in this thread
    for (const inboxRef of inboxMsgsInThread) {
      const detail = getMessageMetadata(inboxRef.id);
      if (!detail) continue;

      const fromHeader = getHeader(detail, "From");
      const fromEmails = extractEmails(fromHeader);

      // Skip messages from self
      if (fromEmails.includes(USER_EMAIL.toLowerCase())) continue;

      const labels: string[] = detail.labelIds || [];
      if (!labels.includes("INBOX")) continue;

      const inboxTime = Number(detail.internalDate);
      if (inboxTime < sentTime) {
        const diffHours = (sentTime - inboxTime) / (1000 * 60 * 60);
        if (diffHours <= 720) {
          responseTimes.push(diffHours);
        }
        break; // one response time per sent message
      }
    }
  }

  const avgResponseHours =
    responseTimes.length > 0
      ? (
          responseTimes.reduce((a, b) => a + b, 0) / responseTimes.length
        ).toFixed(1)
      : "N/A";

  // =============================================
  // FINAL OUTPUT
  // =============================================
  const topRecipientsStr =
    topRecipients.length > 0
      ? topRecipients
          .map(([email, count]) => `${email} (${count})`)
          .join(", ")
      : "N/A";

  console.log("\n");
  console.log(`TotalSent: ${totalSent}`);
  console.log(`TopRecipients: ${topRecipientsStr}`);
  console.log(`ReplyRate: ${replyRate}%`);
  console.log(`AvgResponseTimeHours: ${avgResponseHours}`);

  // Debug
  if (sentDetails.length > 0) {
    console.log("\n[debug] Sample sent message dates:");
    sentDetails.slice(0, 3).forEach((d) => {
      console.log("  -", getHeader(d, "Date"), "|", getHeader(d, "To"));
    });
  }
}

main().catch(console.error);

